/**
 * Worktree-awareness tests for git-validator (#2363)
 *
 * Covers the two halves of the bug:
 *  - OVER-blocking: a feature-branch worktree judged by the primary
 *    tree's protected branch (session dir on main → false BLOCK)
 *  - UNDER-blocking: compound commands (`cd x && git commit`,
 *    `env -u T git push`) skipping validation entirely via the old
 *    startsWith('git') guard
 *
 * child_process is mocked (repo idiom — see lib/git.test.ts) so branch
 * resolution is controlled per-directory. Session-state files are REAL
 * fs writes under a temp $HOME (os.homedir() honors $HOME on POSIX —
 * same technique as mcp-output-transform.test.ts).
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import type { HookContext, HookInput } from '../../types.js';
import {
  gitValidator,
  locateGitSegment,
  resolveEffectiveDir,
} from '../../pretool/bash/git-validator.js';
import { NOOP_CTX } from '../../lib/context.js';
import {
  getStateFilePath,
  mergeSessionState,
  writeSessionStateAtomic,
} from '../../lib/session-state.js';

vi.mock('node:child_process', () => ({
  execFileSync: vi.fn(() => ''),
}));

import { execFileSync } from 'node:child_process';

// =============================================================================
// Test utilities
// =============================================================================

const PROJECT_DIR = '/test/project';
const WORKTREE_DIR = '/test/project/.worktrees/agent-abc123';
const SESSION_ID = 'wt-test-session';

function createBashInput(command: string, overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Bash',
    session_id: SESSION_ID,
    project_dir: PROJECT_DIR,
    tool_input: { command },
    ...overrides,
  };
}

function mainCtx(): HookContext {
  return { ...NOOP_CTX, branch: 'main', projectDir: PROJECT_DIR };
}

/**
 * Mock `git branch --show-current` per directory; `git diff --cached`
 * (atomic-commit analysis) returns empty.
 */
function mockBranches(byDir: Record<string, string>): void {
  vi.mocked(execFileSync).mockImplementation(((
    _cmd: string,
    args: readonly string[],
    opts: { cwd?: string },
  ) => {
    if (args[0] === 'branch') {
      const cwd = opts?.cwd ?? '';
      if (cwd in byDir) return `${byDir[cwd]}\n`;
      throw new Error(`not a git repo: ${cwd}`);
    }
    return '';
  }) as typeof execFileSync);
}

let tmpHome: string;
let prevHome: string | undefined;

beforeEach(() => {
  tmpHome = mkdtempSync(join(tmpdir(), 'gv-wt-'));
  prevHome = process.env.HOME;
  process.env.HOME = tmpHome;
  delete process.env.ORCHESTKIT_PROTECTED_BRANCHES;
  vi.mocked(execFileSync).mockReset();
  vi.mocked(execFileSync).mockReturnValue('');
});

afterEach(() => {
  if (prevHome === undefined) delete process.env.HOME;
  else process.env.HOME = prevHome;
  rmSync(tmpHome, { recursive: true, force: true });
});

function writeShellCwdState(shellCwd: string): void {
  const path = getStateFilePath('project', SESSION_ID, tmpHome);
  const state = mergeSessionState(null, { shell_cwd: shellCwd }, 'project', SESSION_ID);
  writeSessionStateAtomic(path, state);
}

// =============================================================================
// locateGitSegment (pure parsing)
// =============================================================================

describe('locateGitSegment', () => {
  it('finds git at position 0', () => {
    expect(locateGitSegment('git status')).toEqual({ offset: 0, cdTarget: null });
  });

  it('finds git after a leading cd chain and records the cd target', () => {
    const cmd = 'cd /some/dir && git commit -m "fix: x"';
    const loc = locateGitSegment(cmd);
    expect(loc).not.toBeNull();
    expect(loc?.cdTarget).toBe('/some/dir');
    expect(cmd.slice(loc?.offset ?? 0).startsWith('git commit')).toBe(true);
  });

  it('finds git after pwd && (simple quote-free segment)', () => {
    const cmd = 'pwd && git commit -m "fix: y"';
    const loc = locateGitSegment(cmd);
    expect(loc).not.toBeNull();
    expect(cmd.slice(loc?.offset ?? 0).startsWith('git commit')).toBe(true);
  });

  it('finds git behind env -u prefixes', () => {
    const cmd = 'env -u NPM_TOKEN -u GITHUB_PERSONAL_ACCESS_TOKEN git push origin main';
    const loc = locateGitSegment(cmd);
    expect(loc).not.toBeNull();
    expect(cmd.slice(loc?.offset ?? 0).startsWith('git push')).toBe(true);
  });

  it('finds git behind NAME=value assignments, even FOO=git', () => {
    const cmd = 'FOO=git git push origin main';
    const loc = locateGitSegment(cmd);
    expect(loc).not.toBeNull();
    expect(cmd.slice(loc?.offset ?? 0)).toBe('git push origin main');
  });

  it('uses the LAST cd target before git', () => {
    const loc = locateGitSegment('cd /a && cd /b && git commit -m "x"');
    expect(loc?.cdTarget).toBe('/b');
  });

  it('returns null for non-git commands', () => {
    expect(locateGitSegment('npm test')).toBeNull();
    expect(locateGitSegment('github-actions-runner --help')).toBeNull();
  });

  it('bails at quotes before any git segment (gh bodies are prose)', () => {
    expect(
      locateGitSegment('gh issue create --body "do not run git commit here"'),
    ).toBeNull();
  });

  it('bails on subshell/expansion characters before git', () => {
    expect(locateGitSegment('FOO=$BAR git push')).toBeNull();
    expect(locateGitSegment('echo $(git commit)')).toBeNull();
  });

  it('does not scan past a pipe', () => {
    expect(locateGitSegment('echo foo | git commit')).toBeNull();
  });

  it('still matches a git segment that itself contains quotes', () => {
    const cmd = 'git commit -m "feat: thing"';
    expect(locateGitSegment(cmd)).toEqual({ offset: 0, cdTarget: null });
  });
});

// =============================================================================
// resolveEffectiveDir
// =============================================================================

describe('resolveEffectiveDir', () => {
  it('prefers git -C over everything', () => {
    const dir = resolveEffectiveDir(
      'git -C /explicit/path commit -m "x"',
      '/cd/target',
      createBashInput('irrelevant'),
      mainCtx(),
    );
    expect(dir).toBe('/explicit/path');
  });

  it('uses the cd target when no -C is present', () => {
    const dir = resolveEffectiveDir(
      'git commit -m "x"',
      '/cd/target',
      createBashInput('irrelevant'),
      mainCtx(),
    );
    expect(dir).toBe('/cd/target');
  });

  it('resolves relative paths against the project dir', () => {
    const dir = resolveEffectiveDir(
      'git commit -m "x"',
      '.worktrees/agent-x',
      createBashInput('irrelevant'),
      mainCtx(),
    );
    expect(dir).toBe(join(PROJECT_DIR, '.worktrees/agent-x'));
  });

  it('falls back to session-state shell_cwd', () => {
    writeShellCwdState(WORKTREE_DIR);
    const dir = resolveEffectiveDir(
      'git commit -m "x"',
      null,
      createBashInput('irrelevant'),
      mainCtx(),
    );
    expect(dir).toBe(WORKTREE_DIR);
  });

  it('ignores shell_cwd equal to the project dir', () => {
    writeShellCwdState(PROJECT_DIR);
    const dir = resolveEffectiveDir(
      'git commit -m "x"',
      null,
      createBashInput('irrelevant'),
      mainCtx(),
    );
    expect(dir).toBeNull();
  });

  it('returns null with no signal at all', () => {
    const dir = resolveEffectiveDir(
      'git commit -m "x"',
      null,
      createBashInput('irrelevant'),
      mainCtx(),
    );
    expect(dir).toBeNull();
  });
});

// =============================================================================
// gitValidator end-to-end: the #2363 scenarios
// =============================================================================

describe('gitValidator worktree-awareness (#2363)', () => {
  it('OVER-blocking fixed: commit from a feature-branch worktree (shell_cwd) is not blocked', () => {
    writeShellCwdState(WORKTREE_DIR);
    mockBranches({ [WORKTREE_DIR]: 'fix/2360-ship-hook-bundles' });

    const result = gitValidator(
      createBashInput('git commit -m "fix: ship bundles"'),
      mainCtx(),
    );

    expect(result.continue).toBe(true);
    const ctxText = JSON.stringify(result);
    expect(ctxText).toContain('fix/2360-ship-hook-bundles');
    expect(ctxText).not.toContain('BLOCKED');
  });

  it('still blocks when the worktree itself is on a protected branch', () => {
    writeShellCwdState(WORKTREE_DIR);
    mockBranches({ [WORKTREE_DIR]: 'main' });

    const result = gitValidator(
      createBashInput('git commit -m "fix: nope"'),
      mainCtx(),
    );

    expect(result.continue).toBe(false);
    expect(JSON.stringify(result)).toContain('BLOCKED');
  });

  it('fails closed when the effective dir branch is unresolvable', () => {
    writeShellCwdState('/nonexistent/dir');
    mockBranches({}); // every branch lookup throws

    const result = gitValidator(
      createBashInput('git commit -m "fix: nope"'),
      mainCtx(),
    );

    expect(result.continue).toBe(false);
  });

  it('rescues via git -C pointing at a feature-branch dir', () => {
    mockBranches({ '/elsewhere/repo': 'feat/thing' });

    const result = gitValidator(
      createBashInput('git -C /elsewhere/repo push origin feat/thing'),
      mainCtx(),
    );

    expect(result.continue).toBe(true);
  });

  it('rescues via leading cd to a feature-branch dir', () => {
    mockBranches({ [WORKTREE_DIR]: 'fix/some-branch' });

    const result = gitValidator(
      createBashInput(`cd ${WORKTREE_DIR} && git commit -m "fix: x"`),
      mainCtx(),
    );

    expect(result.continue).toBe(true);
  });

  it('UNDER-blocking fixed: pwd && git commit on main is now blocked', () => {
    // No shell_cwd state, no cd target → effective dir is the main project
    const result = gitValidator(
      createBashInput('pwd && git commit -m "fix: evade"'),
      mainCtx(),
    );

    expect(result.continue).toBe(false);
    expect(JSON.stringify(result)).toContain('BLOCKED');
  });

  it('UNDER-blocking fixed: env -u TOKEN git push on main is now blocked', () => {
    const result = gitValidator(
      createBashInput('env -u NPM_TOKEN git push origin main'),
      mainCtx(),
    );

    expect(result.continue).toBe(false);
  });

  it('gh issue create with git words in the body stays silent', () => {
    const result = gitValidator(
      createBashInput('gh issue create --body "never git commit to main"'),
      mainCtx(),
    );

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('feature-branch sessions do zero effective-dir work (no state read)', () => {
    const result = gitValidator(
      createBashInput('git commit -m "feat: normal flow"'),
      { ...NOOP_CTX, branch: 'feat/regular', projectDir: PROJECT_DIR },
    );

    // Not blocked, and no branch lookups were needed at all
    expect(result.continue).toBe(true);
    const branchCalls = vi
      .mocked(execFileSync)
      .mock.calls.filter((c) => (c[1] as string[])[0] === 'branch');
    expect(branchCalls).toHaveLength(0);
  });

  it('commit-message validation now applies through a cd chain', () => {
    mockBranches({ [WORKTREE_DIR]: 'fix/some-branch' });

    const result = gitValidator(
      createBashInput(`cd ${WORKTREE_DIR} && git commit -m "bad message format"`),
      mainCtx(),
    );

    // Rescued from branch protection, but the invalid conventional format
    // is still denied — validation parity with position-0 git commands.
    expect(result.continue).toBe(false);
    expect(JSON.stringify(result)).toContain('INVALID COMMIT FORMAT');
  });
});
